export const PLAN_OPTIONS = ["1 Month", "3 Months", "6 Months", "1 Year"];

export function getPlanEndDate(startDate, plan) {
  const date = new Date(startDate);

  if (plan === "1 Month") {
    date.setMonth(date.getMonth() + 1);
  }

  if (plan === "3 Months") {
    date.setMonth(date.getMonth() + 3);
  }

  if (plan === "6 Months") {
    date.setMonth(date.getMonth() + 6);
  }

  if (plan === "1 Year") {
    date.setFullYear(date.getFullYear() + 1);
  }

  return date.toISOString().split("T")[0];
}

export function getMembershipState(planEnd) {
  if (!planEnd) {
    return { label: "Unknown", tone: "neutral" };
  }

  const today = new Date();
  const endDate = new Date(planEnd);

  today.setHours(0, 0, 0, 0);
  endDate.setHours(0, 0, 0, 0);

  const diffInDays = Math.ceil((endDate - today) / (1000 * 60 * 60 * 24));

  if (diffInDays < 0) {
    return { label: "Expired", tone: "danger" };
  }

  if (diffInDays <= 3) {
    return { label: "Expiring soon", tone: "warning" };
  }

  return { label: "Active", tone: "success" };
}

export function formatDisplayDate(value) {
  if (!value) {
    return "Not recorded";
  }

  return new Intl.DateTimeFormat("en-US", {
    dateStyle: "medium"
  }).format(new Date(`${value}T00:00:00`));
}

export function isAttendedToday(lastAttended) {
  return lastAttended === new Date().toISOString().split("T")[0];
}
